handleServerSelfUpdate implementation in extension-handlers.ts:

  import { spawn, spawnSync } from 'node:child_process';
  import { DEFAULT_PORT, isWindows } from '@opentabs-dev/shared';

  const CLI_PACKAGE_NAME = '@opentabs-dev/cli';

  const handleServerSelfUpdate = async (state: ServerState, id: string | number): Promise<void> => {
    if (!state.serverUpdate) {
      sendToExtension(state, { jsonrpc: '2.0', error: { code: -32603, message: 'No server update available' }, id });
      return;
    }
    // serverSourcePath is already in scope (module-level const at line 47)
    if (!serverSourcePath.includes('node_modules')) {
      sendToExtension(state, { jsonrpc: '2.0', error: { code: -32603, message: 'Cannot self-update a dev install — use git pull' }, id });
      return;
    }

    const { latestVersion } = state.serverUpdate;

    // Run npm install synchronously (fire-and-forget after success; we exit regardless)
    const result = spawnSync('npm', ['install', '-g', `${CLI_PACKAGE_NAME}@${latestVersion}`], {
      stdio: isDev() ? 'inherit' : 'ignore',
      shell: isWindows(),
    });
    if (result.error || (result.status ?? 1) !== 0) {
      sendToExtension(state, { jsonrpc: '2.0', error: { code: -32603, message: `npm install failed (exit ${result.status ?? 'unknown'})` }, id });
      return;
    }

    // Acknowledge the request before exiting
    sendToExtension(state, { jsonrpc: '2.0', result: { ok: true, message: `Updated to v${latestVersion}. Restarting...` }, id });

    // Foreground mode: inform the terminal user
    if (process.stdout.isTTY) {
      process.stdout.write(`Updated to v${latestVersion}. Server restarted in background mode.\n`);
    }

    // Determine port: check PORT env var, fall back to DEFAULT_PORT
    const port = parseInt(process.env.PORT ?? String(DEFAULT_PORT), 10);
    const startArgs = ['start', '--background'];
    if (port !== DEFAULT_PORT) startArgs.push('--port', String(port));

    // Spawn the new server as a detached background process
    const child = spawn('opentabs', startArgs, { detached: true, stdio: 'ignore', shell: isWindows() });
    child.unref();

    // Exit after a brief delay to allow the sendToExtension call to flush
    setTimeout(() => process.exit(0), 200);
  };

Constraints:
- Do NOT import from plugin-management.ts — use spawnSync directly (simpler for a one-time synchronous install)
- The server exits regardless of whether the extension received the response — 200ms is sufficient for WebSocket flush
- In E2E/dev mode (isDev() = true), the npm install still runs but the test infrastructure is expected to provide the server restart. The handler does NOT skip the npm install in dev mode — the dev-only test endpoint (US-004) is the escape hatch for E2E
- Do NOT block the event loop waiting for the response ACK — use setTimeout(process.exit, 200)
- serverSourcePath is already declared at module scope (line 47) — no need to re-declare it
- isDev() is imported from './dev-mode.js' and is already imported in extension-handlers.ts (verify at top of file)

